export const supabase = createClient<Database>(SUPABASE_URL, SUPABASE_PUBLISHABLE_KEY);

// Drug data helper functions
export interface DrugDataParams {
  searchTerm?: string;
  category?: string; 
  limit?: number;
}

export async function fetchDrugs(params: DrugDataParams = {}) {
  const { searchTerm, category, limit = 50 } = params;
  
  let query = supabase.from('drugs').select('*');
  
  if (searchTerm) {
    query = query.or(`name.ilike.%${searchTerm}%,generic_name.ilike.%${searchTerm}%`);
  }
  
  if (category) {
    query = query.eq('category', category);
  }
  
  const { data, error } = await query.limit(limit);
  
  if (error) {
    console.error('Error fetching drugs:', error);
    return null;
  }
  
  return data;
}

export async function fetchDrugById(id: string) {
  const { data, error } = await supabase
    .from('drugs')
    .select('*')
    .eq('id', id)
    .single();
  
  if (error) {
    console.error('Error fetching drug by ID:', error);
    return null;
  }
  
  return data;
}

export async function saveDrugIdentification(identificationData: any) {
  const { data, error } = await supabase
    .from('drug_identifications')
    .insert([identificationData])
    .select();
  
  if (error) {
    console.error('Error saving drug identification:', error);
    return null;
  }
  
  return data;
}
